     /// as `refresh_io_cost * write_rate / block_threshold`.
     #[must_use]
     pub fn expected_loss_block_count(&self, block_threshold: u32, write_rate: f64) -> f64 {
-        if block_threshold == 0 || self.source_block_count == 0 || write_rate <= 0.0 {
